import axios from 'axios';

/**
 * Axios instance that automatically adds JWT token
 * to every request's Authorization header.
 *
 * Usage: import api from '../services/api'
 *        api.get('/api/drivers')
 *        api.post('/api/promo/create', data)
 */
const api = axios.create({
  baseURL: 'http://localhost:8080',
});

// Request interceptor â€” add token to every request
api.interceptors.request.use(
  (config) => {
    const user = localStorage.getItem('zipride_user');
    if (user) {
      const { token } = JSON.parse(user);
      if (token) {
        config.headers.Authorization = `Bearer ${token}`;
      }
    }
    return config;
  },
  (error) => Promise.reject(error)
);

// Response interceptor â€” handle 401/403 errors globally
api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) {
      // Token expired or invalid â€” logout
      localStorage.removeItem('zipride_user');
      window.location.href = '/login';
    }
    if (error.response?.status === 403) {
      alert('Access Denied! You do not have permission to perform this action.');
    }
    return Promise.reject(error);
  }
);

export default api;
